content = open('task/3/EmitIR.cpp').read()

# Fix IfStmt 
old_if = '''void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!thenBb->getTerminator())
    irb.CreateBr(endBb);

  if (elseBb) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!elseBb->getTerminator())
      irb.CreateBr(endBb);
  }

  irb.SetInsertPoint(endBb);
}'''

new_if = '''void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(endBb);

  if (elseBb) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!irb.GetInsertBlock()->getTerminator())
      irb.CreateBr(endBb);
  }

  endBb->insertInto(mCurFunc);
  irb.SetInsertPoint(endBb);
}'''

if old_if in content:
    content = content.replace(old_if, new_if)
    print("IfStmt fixed")
else:
    print("IfStmt NOT FOUND - checking actual content...")
    # Try to find the IfStmt function
    idx = content.find('void\nEmitIR::operator()(IfStmt* obj)')
    print(f"IfStmt found at idx {idx}")
    if idx > 0:
        print(content[idx:idx+500])

open('task/3/EmitIR.cpp', 'w').write(content)
